// Re-assert each run's ensures so the `=~=` triggers fire in this context.
assert(post1_self_.seq@ =~= pre_self_.seq@.update(i as int, out));
assert(post2_self_.seq@ =~= pre_self_.seq@.update(i as int, out));

// Both post-state sequences are extensionally equal to the same `update(i, out)`,
// so by Seq extensionality they are equal to each other.
assert(post1_self_.seq@ =~= post2_self_.seq@);
assert(post1_self_.seq@ == post2_self_.seq@);
